  ('pukao-e9ff7ca9-moex-00001', 'pukao-e9ff7ca9', 'pukao-e9ff7ca9-moex-114-4dccc0e6', 'sub-pukao-e9ff7ca9-01', NULL, 'single_choice', '下列何者不是公部門管理與私部門管理之差異？', '["公部門管理具有獨占特質，而企業管理強調競爭", "公部門管理較可能會有金魚缸效應（goldfish-bowleffect）", "公部門的決策權力較為集中，而企業的決策程序較為分散與繁複", "企業的組織目標較明確，績效較容易衡量"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:27+00:00", "source_pdf_sha1": "c09432b9175f", "answer_pdf_sha1": "dc420f888dc7", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "412", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政學概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "客家事務行政"}'::jsonb, NULL),
  ('pukao-e9ff7ca9-moex-00002', 'pukao-e9ff7ca9', 'pukao-e9ff7ca9-moex-114-4dccc0e6', 'sub-pukao-e9ff7ca9-01', NULL, 'single_choice', '行政學有關政治與行政關係之敘述，下列何者正確？', '["威爾遜（W.Wilson）認為行政是政府行動的廣泛計畫，而政治是廣泛計畫的詳細執行", "行政學在美國總統羅斯福推行新政時期，脫離政治學成為一門獨立的學科", "行政學真正成為一門獨立學科，主要在於新公共管理的提倡之後", "學者古德諾（F.Goodnow）提倡政治與行政二分"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:27+00:00", "source_pdf_sha1": "c09432b9175f", "answer_pdf_sha1": "dc420f888dc7", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "412", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政學概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "客家事務行政"}'::jsonb, NULL)
